mapper.insert:
insert into activity_comment_like (
    comment_id,
    user_id,
    status
) values (
    #{commentId},
    #{userId},
    #{status}
)

mapper.update:
update activity_comment_like
set status = #{status},
    update_time = now()
where comment_id = #{commentId}
  and user_id = #{userId}

